const raw = $input.first().json;
let payload;
if (raw.body?.body && typeof raw.body.body === 'object') {
  payload = raw.body.body;
} else if (raw.body && typeof raw.body === 'object') {
  payload = raw.body;
} else {
  payload = raw;
}
return { json: payload };

const d = $input.first().json;
const inviteeName = d.inviteeName || '';
const inviterName = d.inviterName || 'Your colleague';
const processName = d.processName || 'a workflow process';
const company = d.company || '';
const joinUrl = d.joinUrl || '';
const teamCode = d.teamCode || '';

var greeting = inviteeName ? 'Hi ' + inviteeName + ',' : 'Hi there,';

var html = '<div style="font-family: -apple-system, BlinkMacSystemFont, Segoe UI, Roboto, sans-serif; max-width: 640px; margin: 0 auto; background: #f8fafc; padding: 20px;">' +
  '<div style="background: linear-gradient(135deg, #1e293b, #334155); color: white; padding: 30px; border-radius: 12px 12px 0 0;">' +
    '<p style="margin: 0 0 4px; font-size: 12px; text-transform: uppercase; letter-spacing: 1px; opacity: 0.7;">Team Alignment</p>' +
    '<h1 style="margin: 0; font-size: 22px;">You\'re invited to share your perspective</h1>' +
    (company ? '<p style="margin: 8px 0 0; opacity: 0.8; font-size: 14px;">' + company + '</p>' : '') +
  '</div>' +
  '<div style="background: white; padding: 30px; border-radius: 0 0 12px 12px; box-shadow: 0 2px 8px rgba(0,0,0,0.06);">' +
    '<p style="font-size: 15px; color: #334155;">' + greeting + '</p>' +
    '<p style="font-size: 15px; color: #475569; line-height: 1.6;"><strong>' + inviterName + '</strong> has invited you to participate in a team alignment exercise for <strong>' + processName + '</strong>.</p>' +
    '<p style="font-size: 15px; color: #475569; line-height: 1.6;">Each team member maps the process independently. The AI then compares everyone\'s responses to reveal where your team\'s understanding diverges.</p>' +
    '<div style="margin: 24px 0; padding: 20px; background: #f8fafc; border-radius: 8px; text-align: center;">' +
      '<p style="margin: 0 0 4px; font-size: 12px; color: #94a3b8; text-transform: uppercase; letter-spacing: 0.5px;">Your team code</p>' +
      '<p style="margin: 0; font-size: 28px; font-weight: 700; letter-spacing: 0.15em; color: #6366f1;">' + teamCode + '</p>' +
    '</div>' +
    '<div style="margin: 24px 0; text-align: center;">' +
      '<a href="' + joinUrl + '" style="display: inline-block; padding: 14px 40px; background: linear-gradient(135deg, #6366f1, #4f46e5); color: white; text-decoration: none; border-radius: 8px; font-weight: 600; font-size: 16px;">Start My Assessment</a>' +
    '</div>' +
    '<p style="font-size: 13px; color: #94a3b8; text-align: center;">It takes about 10-15 minutes to complete.</p>' +
  '</div>' +
'</div>';

return {
  json: {
    to: d.inviteeEmail,
    subject: inviterName + ' invited you to a team alignment session - ' + processName,
    html: html
  }
};

const d = $input.first().json;
const creatorName = d.creatorName || 'there';
const respondentName = d.respondentName || 'A team member';
const respondentEmail = d.respondentEmail || '';
const processName = d.processName || 'your process';
const resultsUrl = d.resultsUrl || '';

var respondentInfo = respondentName;
if (respondentEmail) respondentInfo += ' (' + respondentEmail + ')';

var html = '<div style="font-family: -apple-system, BlinkMacSystemFont, Segoe UI, Roboto, sans-serif; max-width: 640px; margin: 0 auto; background: #f8fafc; padding: 20px;">' +
  '<div style="background: linear-gradient(135deg, #1e293b, #334155); color: white; padding: 30px; border-radius: 12px 12px 0 0;">' +
    '<p style="margin: 0 0 4px; font-size: 12px; text-transform: uppercase; letter-spacing: 1px; opacity: 0.7;">Team Alignment</p>' +
    '<h1 style="margin: 0; font-size: 22px;">New response received</h1>' +
  '</div>' +
  '<div style="background: white; padding: 30px; border-radius: 0 0 12px 12px; box-shadow: 0 2px 8px rgba(0,0,0,0.06);">' +
    '<p style="font-size: 15px; color: #334155;">Hi ' + creatorName + ',</p>' +
    '<p style="font-size: 15px; color: #475569; line-height: 1.6;"><strong>' + respondentInfo + '</strong> has submitted their perspective on <strong>' + processName + '</strong>.</p>' +
    '<div style="margin: 24px 0; text-align: center;">' +
      '<a href="' + resultsUrl + '" style="display: inline-block; padding: 14px 40px; background: linear-gradient(135deg, #6366f1, #4f46e5); color: white; text-decoration: none; border-radius: 8px; font-weight: 600; font-size: 16px;">View Results</a>' +
    '</div>' +
    '<p style="font-size: 13px; color: #94a3b8; text-align: center;">Results are available once 2 or more team members have responded.</p>' +
  '</div>' +
'</div>';

return {
  json: {
    to: d.creatorEmail,
    subject: respondentName + ' submitted their perspective - ' + processName,
    html: html
  }
};

const d = $input.first().json;
const creatorName = d.creatorName || 'there';
const processName = d.processName || 'your process';
const responseCount = d.responseCount || 2;
const resultsUrl = d.resultsUrl || '';

var html = '<div style="font-family: -apple-system, BlinkMacSystemFont, Segoe UI, Roboto, sans-serif; max-width: 640px; margin: 0 auto; background: #f8fafc; padding: 20px;">' +
  '<div style="background: linear-gradient(135deg, #059669, #047857); color: white; padding: 30px; border-radius: 12px 12px 0 0;">' +
    '<p style="margin: 0 0 4px; font-size: 12px; text-transform: uppercase; letter-spacing: 1px; opacity: 0.7;">Team Alignment</p>' +
    '<h1 style="margin: 0; font-size: 22px;">Your team results are ready!</h1>' +
  '</div>' +
  '<div style="background: white; padding: 30px; border-radius: 0 0 12px 12px; box-shadow: 0 2px 8px rgba(0,0,0,0.06);">' +
    '<p style="font-size: 15px; color: #334155;">Hi ' + creatorName + ',</p>' +
    '<p style="font-size: 15px; color: #475569; line-height: 1.6;"><strong>' + responseCount + ' team members</strong> have submitted their perspectives on <strong>' + processName + '</strong>. Your alignment analysis is now available.</p>' +
    '<div style="margin: 20px 0; padding: 16px; background: #f0fdf4; border-radius: 8px; border-left: 4px solid #22c55e;">' +
      '<p style="margin: 0; font-size: 14px; color: #166534;"><strong>What you\'ll see:</strong> perception gaps, hidden inefficiencies, and AI-powered recommendations for getting your team aligned.</p>' +
    '</div>' +
    '<div style="margin: 24px 0; text-align: center;">' +
      '<a href="' + resultsUrl + '" style="display: inline-block; padding: 14px 40px; background: linear-gradient(135deg, #059669, #047857); color: white; text-decoration: none; border-radius: 8px; font-weight: 600; font-size: 16px;">View Team Results</a>' +
    '</div>' +
    '<p style="font-size: 13px; color: #94a3b8; text-align: center;">More team members can still submit - results update automatically.</p>' +
  '</div>' +
'</div>';

return {
  json: {
    to: d.creatorEmail,
    subject: 'Team results are ready - ' + responseCount + ' perspectives on ' + processName,
    html: html
  }
};

const d = $input.first().json;
const processName = d.processName || 'your process';
const resultsUrl = d.resultsUrl || '';
const respondentEmails = d.respondentEmails || [];

var items = [];
for (var i = 0; i < respondentEmails.length; i++) {
  var email = respondentEmails[i];
  var html = '<div style="font-family: -apple-system, BlinkMacSystemFont, Segoe UI, Roboto, sans-serif; max-width: 640px; margin: 0 auto; background: #f8fafc; padding: 20px;">' +
    '<div style="background: linear-gradient(135deg, #1e293b, #334155); color: white; padding: 30px; border-radius: 12px 12px 0 0;">' +
      '<p style="margin: 0 0 4px; font-size: 12px; text-transform: uppercase; letter-spacing: 1px; opacity: 0.7;">Team Alignment</p>' +
      '<h1 style="margin: 0; font-size: 22px;">Session closed</h1>' +
    '</div>' +
    '<div style="background: white; padding: 30px; border-radius: 0 0 12px 12px; box-shadow: 0 2px 8px rgba(0,0,0,0.06);">' +
      '<p style="font-size: 15px; color: #334155;">Hi there,</p>' +
      '<p style="font-size: 15px; color: #475569; line-height: 1.6;">The team alignment session for <strong>' + processName + '</strong> has been closed by the session creator.</p>' +
      '<p style="font-size: 15px; color: #475569; line-height: 1.6;">You can still view the final results:</p>' +
      '<div style="margin: 24px 0; text-align: center;">' +
        '<a href="' + resultsUrl + '" style="display: inline-block; padding: 14px 40px; background: linear-gradient(135deg, #6366f1, #4f46e5); color: white; text-decoration: none; border-radius: 8px; font-weight: 600; font-size: 16px;">View Final Results</a>' +
      '</div>' +
      '<p style="font-size: 13px; color: #94a3b8; text-align: center;">Thank you for participating.</p>' +
    '</div>' +
  '</div>';
  items.push({ json: { to: email, subject: 'Team alignment session closed - ' + processName, html: html } });
}

return items;
